package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVParserTest {

    private CSVParser parser;

    @BeforeEach
    public void setUp() {
        parser = Mockito.mock(CSVParser.class, Mockito.CALLS_REAL_METHODS);
    }

    @Test
    public void testGetRecords_multipleRecords() throws Exception {
        CSVRecord rec1 = mock(CSVRecord.class);
        CSVRecord rec2 = mock(CSVRecord.class);
        CSVRecord rec3 = mock(CSVRecord.class);

        when(parser.nextRecord())
                .thenReturn(rec1)
                .thenReturn(rec2)
                .thenReturn(rec3)
                .thenReturn(null);

        List<CSVRecord> records = parser.getRecords();

        assertNotNull(records);
        assertEquals(3, records.size());
        assertSame(rec1, records.get(0));
        assertSame(rec2, records.get(1));
        assertSame(rec3, records.get(2));
        verify(parser, times(4)).nextRecord();
    }

    @Test
    public void testGetRecords_noRecords() throws Exception {
        when(parser.nextRecord()).thenReturn(null);

        List<CSVRecord> records = parser.getRecords();

        assertNotNull(records);
        assertTrue(records.isEmpty());
        verify(parser, times(1)).nextRecord();
    }

    @Test
    public void testNextRecord_privateMethodInvocation() throws Exception {
        // Using reflection to invoke private nextRecord method
        Method nextRecordMethod = CSVParser.class.getDeclaredMethod("nextRecord");
        nextRecordMethod.setAccessible(true);

        // Because nextRecord is non-static and private, we need a real instance.
        // We create a minimal instance with a stubbed Lexer to avoid NPE if needed.
        // Here we mock CSVParser partially to call real nextRecord.

        CSVParser realParser = Mockito.mock(CSVParser.class, Mockito.CALLS_REAL_METHODS);

        // But nextRecord likely depends on internal state; we can only check it does not throw.
        try {
            Object result = nextRecordMethod.invoke(realParser);
            // result can be null or CSVRecord
            assertTrue(result == null || result instanceof CSVRecord);
        } catch (Exception e) {
            fail("Invocation of private nextRecord threw exception: " + e.getMessage());
        }
    }
}
